#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/*
 * Two-Level Paging System Implementation
 * Demonstrates hierarchical page table structure for x86-like systems
 */

#define PAGE_SIZE 4096 // 4KB pages
#define PTE_SIZE 4 // 4 bytes per page table entry
#define ENTRIES_PER_TABLE 1024 // 1024 entries per page table (4KB / 4 bytes)

/* Page Table Entry structure */
typedef struct {
 unsigned int frame_number : 20; // Physical frame number
 unsigned int present : 1; // Page present in memory
 unsigned int writable : 1; // Write permission
 unsigned int user : 1; // User/supervisor mode
 unsigned int dirty : 1; // Page modified
 unsigned int accessed : 1; // Page accessed
 unsigned int cache_disabled : 1;// Cache disabled
 unsigned int unused : 6; // Unused bits
} __attribute__((packed)) PageTableEntry;

/* Page Directory Entry (for two-level paging) */
typedef struct {
 unsigned int page_table_addr : 20; // Physical address of page table
 unsigned int present : 1;
 unsigned int writable : 1;
 unsigned int user : 1;
 unsigned int page_size : 1; // 0 = 4KB, 1 = 4MB
 unsigned int accessed : 1;
 unsigned int dirty : 1;
 unsigned int unused : 6;
} __attribute__((packed)) PageDirEntry;

/* Simulated physical memory */
#define TOTAL_FRAMES 256
typedef struct {
 unsigned char data[PAGE_SIZE];
 int allocated;
} Frame;

Frame physical_memory[TOTAL_FRAMES];

/* Page directory - first level of two-level paging */
PageDirEntry page_directory[ENTRIES_PER_TABLE];

/* Initialize page directory and page tables */
void init_paging_system() {
 printf("Initializing Two-Level Paging System...\n");
 printf(" Page Size: %d bytes\n", PAGE_SIZE);
 printf(" Entries per table: %d\n", ENTRIES_PER_TABLE);
 printf(" Total frames: %d\n\n", TOTAL_FRAMES);

 // Initialize physical frames
 for (int i = 0; i < TOTAL_FRAMES; i++) {
 physical_memory[i].allocated = 0;
 }

 // Initialize page directory
 memset(page_directory, 0, sizeof(page_directory));
}

/* Allocate a physical frame */
int allocate_frame() {
 for (int i = 0; i < TOTAL_FRAMES; i++) {
 if (!physical_memory[i].allocated) {
 physical_memory[i].allocated = 1;
 return i;
 }
 }
 return -1; // No free frames
}

/* Map a virtual page to a physical frame in the two-level page table */
int map_page_two_level(unsigned int virtual_addr, unsigned int frame_num) {
 // Split virtual address into: page_directory_index | page_table_index | offset
 unsigned int pd_index = (virtual_addr >> 22) & 0x3FF; // Top 10 bits
 unsigned int pt_index = (virtual_addr >> 12) & 0x3FF; // Middle 10 bits
 unsigned int offset = virtual_addr & 0xFFF; // Bottom 12 bits

 printf("Mapping virtual page: 0x%08X\n", virtual_addr);
 printf(" PD Index: %u, PT Index: %u, Offset: %u\n", pd_index, pt_index, offset);

 // In a real OS, we would allocate a page table here
 // For simulation, we just mark the entry
 if (page_directory[pd_index].present == 0) {
 // Allocate a new page table (represented by marking present)
 page_directory[pd_index].present = 1;
 page_directory[pd_index].writable = 1;
 page_directory[pd_index].user = 1;
 page_directory[pd_index].page_table_addr = pd_index; // Simplified
 printf(" Allocated new page table for PD index %u\n", pd_index);
 }

 // In real implementation, we'd set up the second-level page table entry
 // Here we simulate by storing in page_directory
 page_directory[pd_index].present = 1;

 printf(" Mapped to frame: %u\n", frame_num);
 return 0;
}

/* Translate virtual address to physical address using two-level paging */
unsigned int translate_address_two_level(unsigned int virtual_addr) {
 // Extract page directory index and page table index
 unsigned int pd_index = (virtual_addr >> 22) & 0x3FF;
 unsigned int pt_index = (virtual_addr >> 12) & 0x3FF;
 unsigned int offset = virtual_addr & 0xFFF;

 printf("Translating virtual address: 0x%08X\n", virtual_addr);
 printf(" PD Index: %u, PT Index: %u, Offset: %u\n", pd_index, pt_index, offset);

 // Check if page directory entry is valid
 if (!page_directory[pd_index].present) {
 printf(" ERROR: Page table not present! (Page Fault)\n");
 return 0xFFFFFFFF; // Page fault
 }

 // In a real implementation, we would:
 // 1. Look up page directory to get page table address
 // 2. Look up page table to get frame number
 // 3. Combine frame number with offset

 // Simulated translation: use pd_index as part of frame calculation
 unsigned int frame_number = (pd_index + pt_index) % TOTAL_FRAMES;
 unsigned int physical_addr = (frame_number << 12) | offset;

 printf(" Frame number: %u\n", frame_number);
 printf(" Physical address: 0x%08X\n", physical_addr);

 return physical_addr;
}

/* Calculate effective memory access time with TLB */
void calculate_effective_access_time() {
 printf("\n=== TLB Performance Analysis ===\n");

 double tlb_hit_time = 20; // nanoseconds (TLB hit)
 double memory_access_time = 100; // nanoseconds (memory access)
 double tlb_miss_penalty = memory_access_time; // Extra time for page table access

 // Without TLB: every memory access needs 2 memory accesses
 double without_tlb = 2 * memory_access_time;
 printf("Without TLB: 2 x %dns = %.0f ns\n", memory_access_time, without_tlb);

 // With TLB - calculate for different hit ratios
 printf("\nWith TLB (effective access time = hit_ratio * TLB_time + (1-hit_ratio) * (TLB_time + 2*memory_time)):\n");

 double hit_ratios[] = {0.5, 0.8, 0.9, 0.95, 0.99};

 for (int i = 0; i < 5; i++) {
 double hr = hit_ratios[i];
 // On TLB hit: 1 memory access + TLB lookup
 // On TLB miss: 2 memory accesses (page table + data) + TLB lookup
 double effective_time = (hr * tlb_hit_time) + 
 ((1 - hr) * (tlb_hit_time + 2 * memory_access_time));
 printf(" Hit ratio %.0f%%: %.1f ns (speedup: %.1fx)\n", 
 hr * 100, effective_time, without_tlb / effective_time);
 }
}

/* Demonstrate inverted page table concept */
void demonstrate_inverted_page_table() {
 printf("\n=== Inverted Page Table Concept ===\n");
 printf("Instead of one page table per process, system has one table\n");
 printf("with one entry per physical frame.\n\n");

 printf("Inverted Table Entry (per frame):\n");
 printf(" - Frame Number: %d\n", 0);
 printf(" - Process ID: PID of owning process\n");
 printf(" - Virtual Page Number: Page number in process\n");
 printf(" - Protection bits: Read/Write/Execute permissions\n");
 printf(" - Valid bit: Whether frame is in use\n");

 printf("\nAdvantages:\n");
 printf(" - Reduces memory overhead for large address spaces\n");
 printf(" - One table instead of one per process\n");

 printf("\nDisadvantages:\n");
 printf(" - More expensive lookup (must search or use hashing)\n");
 printf(" - Cannot share code easily between processes\n");
}

int main() {
 printf("=================================================\n");
 printf(" TWO-LEVEL PAGING SYSTEM IMPLEMENTATION\n");
 printf("=================================================\n\n");

 // Initialize paging system
 init_paging_system();

 // Allocate some frames and map pages
 printf("\n--- Setting up page mappings ---\n");
 int frame1 = allocate_frame();
 int frame2 = allocate_frame();
 int frame3 = allocate_frame();

 // Map virtual address 0x00403000 to frame 5
 map_page_two_level(0x00403000, frame1);
 map_page_two_level(0x00403000 + PAGE_SIZE, frame2);

 printf("\n--- Address Translation Examples ---\n");

 // Translate some addresses
 translate_address_two_level(0x00403000); // Page start
 printf("\n");
 translate_address_two_level(0x00403123); // Middle of page
 printf("\n");
 translate_address_two_level(0x00404000); // Different page

 // Show page fault
 printf("\n--- Page Fault Example ---\n");
 translate_address_two_level(0x12345000); // Unmapped page

 // Calculate performance
 calculate_effective_access_time();

 // Inverted page table explanation
 demonstrate_inverted_page_table();

 printf("\n=================================================\n");
 printf(" Program completed successfully\n");
 printf("=================================================\n");

 return 0;
}
